 63→const ChapterReader = () => {
 64→    const { storyId, chapterId } = useParams();
 65→    const navigate = useNavigate();
 66→    const location = useLocation();
 67→    const { session } = useAuth();
 68→    const token = session?.access_token;
 69→
 70→    const { data: chapter, isLoading } = useChapter(storyId, chapterId, token);
 71→    const { data: commentCounts } = useChapterCommentCounts(chapterId, token);
 72→    const progressTimerRef = useRef(null);
 73→    const scrollRef = useRef(0);
 74→    const bodyRef = useRef(null);
 75→    const hasRestoredRef = useRef(false);
 76→    const [contentReady, setContentReady] = useState(false);
 77→    const [activeComment, setActiveComment] = useState(null);
 78→
 79→    // Save reading progress debounced on scroll
 80→    const saveProgress = useCallback(() => {
 81→        if (!token || !storyId || !chapterId) return;
 82→        saveReadingProgress(token, storyId, chapterId, scrollRef.current).catch(() => {});
 83→    }, [token, storyId, chapterId]);
 84→
 85→    useEffect(() => {
 86→        const handleScroll = () => {
 87→            const scrollTop = window.scrollY || document.documentElement.scrollTop;
 88→            const docHeight = document.documentElement.scrollHeight - window.innerHeight;
 89→            scrollRef.current = docHeight > 0 ? Math.min(scrollTop / docHeight, 1) : 0;
 90→
 91→            if (progressTimerRef.current) clearTimeout(progressTimerRef.current);
 92→            progressTimerRef.current = setTimeout(saveProgress, 3000);
 93→        };
 94→
 95→        window.addEventListener('scroll', handleScroll, { passive: true });
 96→        return () => {
 97→            window.removeEventListener('scroll', handleScroll);
 98→            if (progressTimerRef.current) clearTimeout(progressTimerRef.current);
 99→            // Save on unmount
100→            saveProgress();
101→        };
102→    }, [saveProgress]);
103→
104→    // Restore scroll position when resuming from "Continue Reading"
105→    useEffect(() => {
106→        const savedPosition = location.state?.scrollPosition;
107→        if (!savedPosition || hasRestoredRef.current || !contentReady) return;
108→        hasRestoredRef.current = true;
109→
110→        // Double rAF ensures the browser has painted Lexical content
111→        let raf1, raf2;
112→        raf1 = requestAnimationFrame(() => {
113→            raf2 = requestAnimationFrame(() => {
114→                const docHeight = document.documentElement.scrollHeight - window.innerHeight;
115→                if (docHeight > 0) {
116→                    window.scrollTo({ top: docHeight * savedPosition, behavior: 'instant' });
117→                }
118→                navigate(location.pathname, { replace: true, state: {} });
119→            });
120→        });
121→
122→        return () => {
123→            cancelAnimationFrame(raf1);
124→            cancelAnimationFrame(raf2);
125→        };
126→    }, [contentReady]);
127→
128→    // Reset state when chapter changes
129→    useEffect(() => {
130→        setContentReady(false);
131→        setActiveComment(null);
132→    }, [chapterId]);
133→
134→    // Scroll progress bar
135→    useEffect(() => {
136→        const bar = document.getElementById('chapter-progress-bar');
137→        if (!bar) return;
138→
139→        const updateBar = () => {
140→            const scrollTop = window.scrollY || document.documentElement.scrollTop;
141→            const docHeight = document.documentElement.scrollHeight - window.innerHeight;
142→            const pct = docHeight > 0 ? (scrollTop / docHeight) * 100 : 0;
143→            bar.style.width = `${Math.min(pct, 100)}%`;
144→        };
145→
146→        window.addEventListener('scroll', updateBar, { passive: true });
147→        return () => window.removeEventListener('scroll', updateBar);
148→    }, []);
149→
150→    const editorConfig = {
151→        namespace: 'ChapterReader',
152→        theme: readerTheme,
153→        nodes: [ImageNode, HeadingNode, QuoteNode],
154→        editable: false,
155→        onError(error) { console.error('Lexical error:', error); },
156→    };
157→
158→    if (isLoading) {
159→        return (
160→            <div className="chapter-reader">
161→                <div className="chapter-reader-loading">
162→                    <BeatLoader size={10} color="var(--text-muted)" />
163→                </div>
164→            </div>
165→        );
166→    }
167→
168→    if (!chapter) {
169→        return (
170→            <div className="chapter-reader">
171→                <p className="chapter-reader-error">Chapter not found.</p>
172→            </div>
173→        );
174→    }
175→
176→    const prevCh = chapter.prev_chapter;
177→    const nextCh = chapter.next_chapter;
178→
179→    return (
180→        <motion.div
181→            className="chapter-reader"
182→            initial={{ opacity: 0 }}
183→            animate={{ opacity: 1 }}
184→            transition={{ duration: 0.2 }}
185→        >
186→            {/* Progress bar */}
187→            <div className="chapter-progress-track">
188→                <div id="chapter-progress-bar" className="chapter-progress-fill" />
189→            </div>
190→
191→            {/* Header */}
192→            <div className="chapter-reader-header">
193→                <button
194→                    className="chapter-reader-back"
195→                    onClick={() => navigate(`/home/stories/${storyId}`)}
196→                >
197→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
198→                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
199→                    </svg>
200→                </button>
201→                <div className="chapter-reader-header-info">
202→                    <span className="chapter-reader-chapter-label">Chapter {chapter.chapter_number}</span>
203→                    <h1 className="chapter-reader-title">{chapter.title}</h1>
204→                </div>
205→            </div>
206→
207→            {/* Content */}
208→            <div className="chapter-reader-body" ref={bodyRef}>
209→                <LexicalComposer initialConfig={editorConfig}>
210→                    <ReaderContent chapter={chapter} onContentReady={() => setContentReady(true)} />
211→                </LexicalComposer>
212→                <ParagraphCommentLayer
213→                    containerRef={bodyRef}
214→                    commentCounts={commentCounts}
215→                    onParagraphClick={setActiveComment}
216→                />
217→            </div>
218→
219→            {/* Comment Panel */}
220→            <AnimatePresence>
221→                {activeComment && (
222→                    <CommentPanel
223→                        chapterId={chapterId}
224→                        activeComment={activeComment}
225→                        onClose={() => setActiveComment(null)}
226→                    />
227→                )}
228→            </AnimatePresence>
229→
230→            {/* Navigation */}
231→            <div className="chapter-reader-nav">
232→                {prevCh ? (
233→                    <button
234→                        className="chapter-nav-btn chapter-nav-prev"
235→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${prevCh.id}`)}
236→                    >
237→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
238→                            <path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/>
239→                        </svg>
240→                        <span>Ch. {prevCh.chapter_number}: {prevCh.title}</span>
241→                    </button>
242→                ) : <div />}
243→                {nextCh ? (
244→                    <button
245→                        className="chapter-nav-btn chapter-nav-next"
246→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${nextCh.id}`)}
247→                    >
248→                        <span>Ch. {nextCh.chapter_number}: {nextCh.title}</span>
249→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
250→                            <path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z"/>
251→                        </svg>
252→                    </button>
253→                ) : <div />}
254→            </div>
255→        </motion.div>
256→    );
257→};
