// Restore scroll position when resuming from "Continue Reading"
useEffect(() => {
    const savedPosition = location.state?.scrollPosition;  // LINE 106
    if (!savedPosition || hasRestoredRef.current || !contentReady) return;
    hasRestoredRef.current = true;

    // Double rAF ensures the browser has painted Lexical content
    let raf1, raf2;
    raf1 = requestAnimationFrame(() => {
        raf2 = requestAnimationFrame(() => {
            const docHeight = document.documentElement.scrollHeight - window.innerHeight;
            if (docHeight > 0) {
                window.scrollTo({ top: docHeight * savedPosition, behavior: 'instant' });  // LINE 116
            }
            navigate(location.pathname, { replace: true, state: {} });  // LINE 118 - clears state
        });
    });

    return () => {
        cancelAnimationFrame(raf1);
        cancelAnimationFrame(raf2);
    };
}, [contentReady]);  // LINE 126 - triggered when content is ready
